1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_THRESHOLD = 2;
4	const LOYALTY_DISCOUNT = 0.2;
5	const FOLLOWUP_DISCOUNT = 0.15;
6	
7	interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Customer {
20	  yearsWithMHPCO: number;
21	}
22	
23	interface Scenario {
24	  customer: Customer;
25	  steps: QuoteStep[];
26	}
27	
28	interface QuoteResult {
29	  premium: number;
30	}
31	
32	const COMPONENT_BASE_PREMIUM = 25;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: COMPONENT_BASE_PREMIUM,
40	  moonstone: COMPONENT_BASE_PREMIUM,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const formsBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const typeBasePremium = (type: string, count: number): number => {
51	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
52	  return count * BASE_PREMIUMS[type];
53	};
54	
55	const countByType = (items: Item[]): Map<string, number> =>
56	  items.reduce(
57	    (counts, item) =>
58	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
59	    new Map<string, number>(),
60	  );
61	
62	const policyBasePremium = (items: Item[]): number =>
63	  [...countByType(items)].reduce(
64	    (base, [type, count]) => base + typeBasePremium(type, count),
65	    0,
66	  );
67	
68	// A rate rule contributes its rate to a subject only when it applies.
69	interface RateRule<T> {
70	  applies: (subject: T) => boolean;
71	  rate: number;
72	}
73	
74	const sumApplicableRates = <T>(rules: RateRule<T>[], subject: T): number =>
75	  rules.reduce(
76	    (rate, rule) => (rule.applies(subject) ? rate + rule.rate : rate),
77	    0,
78	  );
79	
80	const CURSE_SURCHARGE = 0.5;
81	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
82	const HIGH_ENCHANTMENT_THRESHOLD = 5;
83	
84	const SURCHARGE_RULES: RateRule<Item>[] = [
85	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
86	  {
87	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
88	    rate: HIGH_ENCHANTMENT_SURCHARGE,
89	  },
90	];
91	
92	const itemSurchargeRate = (item: Item): number =>
93	  sumApplicableRates(SURCHARGE_RULES, item);
94	
95	const itemSurcharge = (item: Item): number =>
96	  itemSurchargeRate(item) * BASE_PREMIUMS[item.type];
97	
98	const itemSurcharges = (items: Item[]): number =>
99	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
100	
101	interface PolicyContext {
102	  customer: Customer;
103	  isFollowUp: boolean;
104	}
105	
106	// Policy-wide modifiers each apply a signed rate to the policy base:
107	// positive rates are surcharges, negative rates are discounts.
108	const POLICY_MODIFIER_RULES: RateRule<PolicyContext>[] = [
109	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
110	  {
111	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
112	    rate: -LOYALTY_DISCOUNT,
113	  },
114	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
115	];
116	
117	const policyModifierRate = (context: PolicyContext): number =>
118	  sumApplicableRates(POLICY_MODIFIER_RULES, context);
119	
120	// A signed modifier rate scales a base: positive rates surcharge, negative discount.
121	const applyModifierRate = (base: number, rate: number): number =>
122	  base * (1 + rate);
123	
124	// Premiums round up (in the MHPCO's favor); toFixed guards against
125	// floating-point error nudging an exact value over an integer boundary.
126	const roundUpPremium = (amount: number): number =>
127	  Math.ceil(Number(amount.toFixed(6)));
128	
129	const quotePremium = (step: QuoteStep, context: PolicyContext): number => {
130	  const { items } = step;
131	  const policyBase = policyBasePremium(items);
132	  // Policy modifiers scale the policy base only; item surcharges are added
133	  // separately (outside the modifier scope), then the flat fee comes last.
134	  const modifiedPolicyBase = applyModifierRate(policyBase, policyModifierRate(context));
135	  const total = modifiedPolicyBase + itemSurcharges(items) + PROCESSING_FEE;
136	  return roundUpPremium(total);
137	};
138	
139	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
140	  // Every step is a quote for now, so the first quote is the first step.
141	  // When claim steps interleave, derive isFollowUp from prior quotes instead.
142	  const results = scenario.steps.map((step, index) => {
143	    const isFollowUp = index > 0;
144	    const context: PolicyContext = { customer: scenario.customer, isFollowUp };
145	    return { premium: quotePremium(step, context) };
146	  });
147	  return { results };
148	};
